# words 251-325
B6 = {
251: {"nativeDefinition": "At the same level or standard as something.", "japaneseMeaning": "（〜と）同等の、同レベルの", "etymology": "on par with（〜と同じパー）のゴルフ用語から一般化。", "examples": {"B": "最近この新しい検索エンジン使ってる。結果はGoogleと同等だけど、Googleアカウントとかがなくて快適。", "C": "ここ数年ボイストレーニングしてきたけど、プロ歌手にはまだ及ばない。", "D": "何かと同じレベルで。"}},
252: {"nativeDefinition": "To push through something difficult with determination.", "japaneseMeaning": "（困難を）力強く乗り越える、押し切る", "etymology": "power through（力で通す）の口語表現。", "examples": {"B": "あのモッシュは命の恩人だった。寝なくても一日乗り切れた。", "C": "やる気があるうちに押し切って終わらせよう。鉄は熱いうちに打て。", "D": "力強く何かを進める。"}},
253: {"nativeDefinition": "To provide someone with something, often through connections.", "japaneseMeaning": "（人に何かを）用意してあげる、つなぐ", "etymology": "hook up（つなぐ）のスラング用法。", "examples": {"B": "高給の仕事、つないでくれない？経験はないけど学ぶ意欲はある。", "C": "コネ使えばフロントのチケット手に入れられるけど、法外な値段になるよ。いい？", "D": "誰かのために何かを手配する。"}},
254: {"nativeDefinition": "To reach the highest point of ability or popularity.", "japaneseMeaning": "ピークを迎える、最高潮に達する", "etymology": "peak（頂点）の動詞用法。", "examples": {"B": "彼女、ずっと前にピーク迎えたよね。新曲聞かない。", "C": "プロサッカー選手は25〜27歳でピークを迎えるらしい。若いね。", "D": "可能な限り最高レベルに達する。"}},
255: {"nativeDefinition": "To inform on someone; a person who informs.", "japaneseMeaning": "密告する、スニッチ", "etymology": "snitch（こっそり告げ口する）のスラング。", "examples": {"B": "友達が宿題コピーしたこと密告した。裏切られた気分。", "C": "マークが密告者だと思う？会議中にネットショッピングしてたって上司に言われた。君じゃないよね？", "D": "密告者。"}},
256: {"nativeDefinition": "From a different perspective or viewpoint.", "japaneseMeaning": "別の視点から、違うレンズで見て", "etymology": "through a different lens（違うレンズを通して）の比喩。", "examples": {"B": "外国語を学ぶと賢くなるかはわからないけど、世界を違う視点で見られるようになる。", "C": "問題を違う視点で見たら、核心にたどり着けた。", "D": "異なる視点から。"}},
257: {"nativeDefinition": "A temporary failure to think or remember.", "japaneseMeaning": "頭が真っ白、ブレインファート", "etymology": "brain fart（脳のおなら）のユーモラスな造語。", "examples": {"B": "やばい、頭が真っ白。ディズニーの有名なネズミの名前なんだっけ？", "C": "ステージで頭が真っ白になって恥をかきたくないから、原稿読むことにした。", "D": "一時的な思考停止。"}},
258: {"nativeDefinition": "To have a very kind and generous nature.", "japaneseMeaning": "心の底が優しい、金の心を持つ", "etymology": "heart of gold（金の心）の直訳的慣用表現。", "examples": {"B": "ステイシはいつも彼氏が心優しいって言うけど、実際に誰かに親切なとこ見たことない。", "C": "ライアン、本当に心優しいよね。いつも他人のことを考えてる。", "D": "寛大で優しい性質を持つ。"}},
259: {"nativeDefinition": "To claim the right to something before others.", "japaneseMeaning": "（何かを）取り置きする、先に取る", "etymology": "call dibs（取り置きを宣言する）の子供言葉から。", "examples": {"B": "最後のピザ、取り置きした。午後のトレーニングにエネルギー必要だから。", "C": "うちの犬、いつも助手席を取り置きするから、俺は後部座席。", "D": "何かの権利を主張する。"}},
260: {"nativeDefinition": "To doubt or question a decision or someone.", "japaneseMeaning": "（決定などを）再考する、疑う", "etymology": "second-guess（二回推測する）で、後から疑う意味。", "examples": {"B": "いつも自分の決断を疑っちゃう。もっと自信がほしい。", "C": "fortyのスペル、いつも二回確認する。fourみたいにuがないから。", "D": "何かを疑う。"}},
261: {"nativeDefinition": "In someone's opinion or judgment.", "japaneseMeaning": "（人の）目には、〜と思う", "etymology": "in one's eyes（人の目に）で、主観的評価を表す。", "examples": {"B": "マイケル・ジョーダンは俺の中では史上最高の選手。", "C": "彼女は俺の目にはいつも完璧。", "D": "誰かの意見において。"}},
262: {"nativeDefinition": "Something that makes a good situation even better.", "japaneseMeaning": "さらに良くするもの、最高の仕上げ", "etymology": "icing on the cake（ケーキのトッピング）の慣用表現。", "examples": {"B": "カフェのコーヒーは最高で、リラックスできる雰囲気がさらに良かった。", "C": "修士号は採用の足がかりになる？それとも錦上添花？", "D": "状況をさらに良くするもの。"}},
263: {"nativeDefinition": "To make a great effort to help or please someone.", "japaneseMeaning": "（人のために）全力を尽くす、ひねり返す", "etymology": "bend over backwards（後ろに反る）の比喩で、多大な努力を表す。", "examples": {"B": "彼女に完全に従ってるじゃん。頼まれること全部全力でやってるでしょ。", "C": "全力で助けたのに感謝もされないの、本当に嫌だ。", "D": "あらゆる努力をする。"}},
264: {"nativeDefinition": "Do what you want; I won't judge you.", "japaneseMeaning": "君は君のやり方で、好きにして", "etymology": "you do you（あなたはあなたをする）のミレニアル世代スローガン。", "examples": {"B": "この高級フレンチレストランでノートPC使うの？変な目で見られるよ。でも好きにして。", "C": "本当にもっとチーズ入れるの？十分でしょ。でも好きにして。", "D": "好きにしなさい。"}},
265: {"nativeDefinition": "To watch carefully; to stay alert.", "japaneseMeaning": "目を光らせる、注意して見ておく", "etymology": "keep one's eyes peeled（目を剥く）の慣用表現。", "examples": {"B": "新しいエピソード出るから、目を光らせておかないと。", "C": "仕事探してるんだね。良いの見つけたら教えるよ。", "D": "気をつけて！"}},
266: {"nativeDefinition": "To make oneself cleaner or more presentable.", "japaneseMeaning": "身だしなみを整える、さっぱりする", "etymology": "freshen up（新鮮にする）の直訳的表現。", "examples": {"B": "ディナーに行く前に、少し身だしなみ整えさせて。", "C": "ワークアウト終わった。さっぱりするから、準備できたら連絡する。", "D": "自分をきれいにする。"}},
267: {"nativeDefinition": "Almost remembered but not quite.", "japaneseMeaning": "喉まで出かかっている、思い出せそうで思い出せない", "etymology": "on the tip of one's tongue（舌の先に）の慣用表現。", "examples": {"B": "ルーシーの名字、喉まで出かかってる。Aで始まるのは確かだけど、あとは出てこない。", "C": "あ、この人知ってる。名前なんだっけ？喉まで出かかってるのに出てこない。", "D": "もう少しで思い出せそう。"}},
268: {"nativeDefinition": "To notice oneself doing something unconsciously.", "japaneseMeaning": "（自分が〜していることに）気づく", "etymology": "catch oneself doing（自分が〜するのを捕まえる）の表現。", "examples": {"B": "運転中にボーッとしてる自分に気づくことが多い。まだ生きてるの不思議。もっと気をつけないと。", "C": "緊張やストレスのとき、口の中側を噛んでる自分に気づく。なんでだろう。", "D": "自分が〜していることに気づく。"}},
269: {"nativeDefinition": "To lower oneself to someone's bad behavior level.", "japaneseMeaning": "（人の）レベルに堕ちる、同じ土俵に立つ", "etymology": "sink to one's level（人のレベルに沈む）の比喩。", "examples": {"B": "お前のレベルに堕ちてネットでケンカするつもりはない。お前誰だよ。俺には人生がある。", "C": "仕返しに時間を使いたくない。相手のレベルに堕ちたくない。", "D": "人と同じ低い行動をする。"}},
270: {"nativeDefinition": "To amaze or impress someone greatly.", "japaneseMeaning": "（人を）驚かせる、圧倒する", "etymology": "blow away（吹き飛ばす）の比喩的用法。", "examples": {"B": "この超リアルな絵、圧倒された。一見写真かと思ったけど、鉛筆画だった。", "C": "トイレ掃除から始まって社長になった。本当にすごい。", "D": "誰かを驚かせる。"}},
271: {"nativeDefinition": "Avoiding language that might offend particular groups.", "japaneseMeaning": "政治的に正しい、配慮した言葉遣い", "etymology": "politically correct（政治的に正しい）の社会用語。", "examples": {"B": "最近は政治的に正しすぎる気がする。みんないつも言葉を監視し合ってる。", "C": "日本人をjapsって呼ぶの、政治的に正しくないと思う。", "D": "攻撃的でない。"}},
272: {"nativeDefinition": "Consecutively without a break.", "japaneseMeaning": "連続で、ずっと", "etymology": "straight（まっすぐ）が「連続して」という副詞用法。", "examples": {"B": "大言壮語かもしれないけど、2〜3週間何も食べずにいける自信ある。", "C": "20日連続で働いてる。週末は髪を下ろしたい。", "D": "連続して。"}},
273: {"nativeDefinition": "Fortunately, something happened.", "japaneseMeaning": "〜してくれてよかった、幸い〜した", "etymology": "good thing（良いこと）で、幸いな結果を表す。", "examples": {"B": "昨夜すごく疲れてアラーム設定し忘れた。よかった早起きした。", "C": "一緒にいてくれてよかった。あの怖い男に一人では立ち向かえなかった。", "D": "幸い何かがそうする。"}},
274: {"nativeDefinition": "Simplicity is better; less is more effective.", "japaneseMeaning": "少ないほうがいい、シンプルイズベスト", "etymology": "less is more（少ないほうが多い）のデザイン原則から。", "examples": {"B": "校長はいつも長話。要点を言えよ。少ないほうがいいってわかってない。", "C": "俺は少ないほうがいいと信じてる。だからアパートにはソファとテーブルだけ。", "D": "シンプルなほうがいい。"}},
275: {"nativeDefinition": "Completely deserted and empty.", "japaneseMeaning": "ガラガラ、誰もいない", "etymology": "like a ghost town（お化け城のように）の比喩。", "examples": {"B": "今朝のコストコ、ガラガラだった。天気のせいかも。", "C": "クリスマス後、観光客が帰るとこのレストランはガラガラになる。", "D": "人けがない。"}},
276: {"nativeDefinition": "To make someone feel uncomfortable or uneasy.", "japaneseMeaning": "（人を）気持ち悪がらせる、ゾッとさせる", "etymology": "weird out（変にする）の口語表現。", "examples": {"B": "コニーがなんで急にキッチンで踊り始めたの？君も気持ち悪くなった？", "C": "青信号が気持ち悪い。いつも黄色だと思ってる。", "D": "誰かを不快にさせる。"}},
277: {"nativeDefinition": "To end a relationship with someone.", "japaneseMeaning": "（人と）縁を切る、関係を断つ", "etymology": "cut ties（絆を切る）の直訳的表現。", "examples": {"B": "ピートが突然縁を切った理由がわからない。コーヒーかスカーフのどっちかかな。", "C": "ジョシュとは縁を切った。彼女へのサプライズをバラしたから。2ヶ月以上準備してたのに。", "D": "誰かとの関係を終わらせる。"}},
278: {"nativeDefinition": "To dislike someone and treat them unfairly.", "japaneseMeaning": "（人に）意地悪する、恨みを持っている", "etymology": "have it in for（〜に対してある）で、意地悪な意図を持つ意味。", "examples": {"B": "また？なんでポールが君に意地悪してると思う？先週話したけど、親友みたいに言ってたよ。", "C": "怒鳴られたからって、意地悪してるとは限らないよ。", "D": "嫌ったり恨みを持ったりする。"}},
279: {"nativeDefinition": "A person who seems like a friend but is actually an enemy.", "japaneseMeaning": "フレネミー、敵か味方かわからない人", "etymology": "friend（友達）＋enemy（敵）の造語。", "examples": {"B": "アイスクリームはフレネミー。美味しいけど太る。", "C": "大学の友達のパーティー行くことになってるけど、あまり行きたくない。どっちつかずの関係だし。何て断ろう。", "D": "友達のふりをする敵。"}},
280: {"nativeDefinition": "Forgetful or not paying attention.", "japaneseMeaning": "ぼんやりした、忘れっぽい", "etymology": "absent-minded（心が不在の）の直訳的表現。", "examples": {"B": "最近かなりぼんやりしてる。年のせいかな。", "C": "すごく忘れっぽい。スマホ探すのに20分かかった。目の前にあった。", "D": "不注意な。"}},
281: {"nativeDefinition": "An imagination that exaggerates things.", "japaneseMeaning": "想像力豊かすぎる、大げさに想像する", "etymology": "overactive imagination（過剰に活動する想像力）の表現。", "examples": {"B": "暗闇が怖いときがある。想像力が豊かすぎて、影に何か隠れてると思っちゃう。", "C": "あの雲、ドラゴンに見えない？俺の想像力が豊かすぎるだけか。", "D": "物事を誇張する想像力。"}},
282: {"nativeDefinition": "To publicly reject or boycott someone.", "japaneseMeaning": "（人を）キャンセルする、追放する", "etymology": "cancel（キャンセル）がSNS時代の追放行為を指す。", "examples": {"B": "このコメディアン、キャンセルされて魂の浄化の巡礼に出た。あまり効果なさそう。", "C": "ひどい性差別発言が最後の一押し。彼はキャンセルだ。", "D": "誰かを追放する。"}},
283: {"nativeDefinition": "A dominant, confident person (especially a man).", "japaneseMeaning": "アルファ、支配的な人", "etymology": "alpha（アルファ）が動物の社会階級から人間にも使われる。", "examples": {"B": "アルファ男性だって言いふらしても、アクションが伴わなきゃ意味ない。", "C": "ジョシュは賢くて自信があって勇敢で、女性に慕われてる。間違いなくアルファだ。", "D": "支配的な人。"}},
284: {"nativeDefinition": "To advance through promotions in a company.", "japaneseMeaning": "出世する、コーポレートラダーを登る", "etymology": "corporate ladder（企業のはしご）の比喩的表現。", "examples": {"B": "昔は出世に夢中だったけど、長男が生まれて仕事以外にも人生があると気づいた。", "C": "父は選択肢は2つだと言った。出世するか、自分のビジネスを作るか。2週間悩んで辞めた。", "D": "昇進を重ねて会社で進む。"}},
285: {"nativeDefinition": "The most effective or recommended way to do something.", "japaneseMeaning": "ベストプラクティス、最善の方法", "etymology": "best practice（最良の実践）のビジネス用語。", "examples": {"B": "米を炊く前に洗うのがベストプラクティスだけど、めんどくさい。", "C": "ミニマリストのベストプラクティスを学びたいならこの動画見て。", "D": "理想的なプロセス。"}},
286: {"nativeDefinition": "To do something without real effort or enthusiasm.", "japaneseMeaning": "形だけこなす、やる気なくやる", "etymology": "go through the motions（動作をこなす）の慣用表現。", "examples": {"B": "来週辞めるから、今は形だけこなしてる。上司が喜ぶかどうかもうどうでもいい。", "C": "成功する選手は練習で形だけこなすことはない。", "D": "あまり努力せずに何かをする。"}},
287: {"nativeDefinition": "An attractive older man with gray or silver hair.", "japaneseMeaning": "シルバーフォックス、白髪のイケオジ", "etymology": "silver（銀色）＋fox（キツネ）で、魅力的な年配男性を指す。", "examples": {"B": "今の人生目標は、セクシーで物知りなシルバーフォックスになること。", "C": "この写真の父、シルバーフォックスに見えるって思うでしょ？会ったらがっかりするよ。", "D": "ハンサムな年配の男性。"}},
288: {"nativeDefinition": "Not while someone is in charge or responsible.", "japaneseMeaning": "（人が）見ているうちは許さない、私がいる限り", "etymology": "not on one's watch（見張り中ではない）の表現。", "examples": {"B": "母がお気に入りのぬいぐるみ捨てようとした。俺がいる限り許さない。", "C": "差別的な発言は、私が責任者の間は許さない。", "D": "誰かが責任者の間は。"}},
289: {"nativeDefinition": "To be unaware of the world outside one's own experience.", "japaneseMeaning": "自分の世界に閉じこもっている、世間知らず", "etymology": "live in a bubble（泡の中に住む）の比喩。", "examples": {"B": "自分の世界に閉じこもってると、他の人の苦労がわからない。", "C": "田舎育ちだから、都会のことはよくわからない。泡の中にいた。", "D": "自分の世界しか知らない。"}},
290: {"nativeDefinition": "High expectations to meet when replacing someone successful.", "japaneseMeaning": "大きな靴を履く、高い期待に応える", "etymology": "big shoes to fill（埋める大きな靴）の慣用表現。", "examples": {"B": "前任者の後任は大きな靴を履くことになる。", "C": "彼の後を継ぐのは大変。期待が高すぎる。", "D": "応えるべき高い期待。"}},
291: {"nativeDefinition": "To start over or reset a situation.", "japaneseMeaning": "リセットする、やり直す", "etymology": "hit the reset button（リセットボタンを押す）の比喩。", "examples": {"B": "関係をリセットする時が来た。", "C": "プロジェクトがうまくいかないから、リセットボタンを押そう。", "D": "やり直す。"}},
292: {"nativeDefinition": "Nothing is better than this.", "japaneseMeaning": "〜に勝るものはない", "etymology": "there's nothing like（〜のようなものはない）の強調表現。", "examples": {"B": "温泉に勝るものはない。", "C": "ホットコーヒーに勝るものはない、冬の朝は。", "D": "何かが最高だ。"}},
293: {"nativeDefinition": "Something that makes people cry emotionally.", "japaneseMeaning": "泣ける作品、涙を誘うもの", "etymology": "tear-jerker（涙を引き出すもの）の造語。", "examples": {"B": "この映画、本当に泣ける。", "C": "あのドラマは最高の泣ける作品だった。", "D": "泣かせるもの。"}},
294: {"nativeDefinition": "To put it mildly; understating something.", "japaneseMeaning": "控えめに言っても、遠慮なく言えば", "etymology": "to put it mildly（穏やかに言えば）の婉曲表現。", "examples": {"B": "控えめに言っても、彼の行動は問題だった。", "C": "遠慮なく言えば、あのプレゼンは最悪だった。", "D": "控えめに言って。"}},
295: {"nativeDefinition": "To admire or worship someone excessively.", "japaneseMeaning": "（人を）神格化する、崇拝する", "etymology": "put on a pedestal（台座に乗せる）の比喩。", "examples": {"B": "有名人を神格化しすぎないほうがいい。", "C": "彼女を台座に乗せすぎてる。人間なんだから。", "D": "誰かを崇拝する。"}},
296: {"nativeDefinition": "Not naturally suited to do something.", "japaneseMeaning": "〜向きじゃない、才能がない", "etymology": "not cut out to（切り出されていない）で、適性がないことを表す。", "examples": {"B": "営業は俺向きじゃない。", "C": "彼は管理職向きじゃない。人を率いるのが苦手。", "D": "〜するために必要な資質がない。"}},
297: {"nativeDefinition": "A person who prefers to be alone.", "japaneseMeaning": "一匹狼、単独行動派", "etymology": "lone wolf（一匹狼）の直訳的表現。", "examples": {"B": "俺は一匹狼タイプ。グループより一人が好き。", "C": "彼は一匹狼だけど、仕事はできる。", "D": "一人でいることを好む人。"}},
298: {"nativeDefinition": "Everything of value has a cost.", "japaneseMeaning": "タダより高いものはない", "etymology": "no such thing as a free lunch（無料の昼食などない）の慣用表現。", "examples": {"B": "タダの昼食なんてない。何かの代償はある。", "C": "無料のサービスには必ず裏がある。", "D": "価値のあるものにタダはない。"}},
299: {"nativeDefinition": "Suffering is necessary to achieve something.", "japaneseMeaning": "痛みなくして得なし", "etymology": "no pain no gain（痛みなくして得なし）のフィットネススローガン。", "examples": {"B": "筋トレは痛みなくして得なし。", "C": "成功には痛みなくして得なし。", "D": "苦しみは達成に必要。"}},
300: {"nativeDefinition": "An acceptable cost for a desired outcome.", "japaneseMeaning": "安い代償、割に合うコスト", "etymology": "a small price to pay（払うには小さな代償）の表現。", "examples": {"B": "夢を叶えるためなら、それは安い代償だ。", "C": "健康のためなら、少しの我慢は安い代償。", "D": "受け入れられるコスト。"}},
301: {"nativeDefinition": "To establish something firmly.", "japaneseMeaning": "（地位などを）固める、確立する", "etymology": "cement（セメント）の比喩で、しっかり固定する意味。", "examples": {"B": "この勝利で地位を固めた。", "C": "契約で関係を固める。", "D": "何かをしっかり確立する。"}},
302: {"nativeDefinition": "To encounter an unexpected problem.", "japaneseMeaning": "思わぬ問題にぶつかる、障害に遭う", "etymology": "hit a snag（引っかかりにぶつかる）の慣用表現。", "examples": {"B": "プロジェクトが思わぬ問題にぶつかった。", "C": "計画は順調だったけど、最後に障害に遭った。", "D": "予期しない問題に遭遇する。"}},
303: {"nativeDefinition": "Firmly established and difficult to change.", "japaneseMeaning": "根深い、根強い", "etymology": "deep-rooted（深く根ざした）の直訳的表現。", "examples": {"B": "この問題は根深い。", "C": "根深い偏見を変えるのは難しい。", "D": "深く根ざした。"}},
304: {"nativeDefinition": "By itself; exactly; in itself.", "japaneseMeaning": "それ自体では、厳密には", "etymology": "per se（それ自体で）のラテン語表現。", "examples": {"B": "お金自体は悪じゃない。", "C": "それ自体では問題ない。", "D": "正確に。"}},
305: {"nativeDefinition": "Expressing regret about missed opportunities (woulda, shoulda, coulda).", "japaneseMeaning": "〜すればよかった、後悔の言葉", "etymology": "woulda shoulda coulda（したかった、すべきだった、できた）の口語省略。", "examples": {"B": "あの時買えばよかった、典型の後悔だ。", "C": "woulda shoulda coulda、もう遅い。", "D": "後悔。"}},
306: {"nativeDefinition": "A long, complicated story or series of events.", "japaneseMeaning": "長話、一大騒動", "etymology": "saga（サガ）が北欧の英雄叙事詩から長い物語全般を指す。", "examples": {"B": "この騒動、長いサガになりそう。", "C": "彼女との関係は長いサガだった。", "D": "長く複雑な話。"}},
307: {"nativeDefinition": "To become more sociable and less shy.", "japaneseMeaning": "殻から出る、社交的になる", "etymology": "come out of one's shell（殻から出る）の比喩。", "examples": {"B": "大学で殻から出て、友達が増えた。", "C": "彼は最近殻から出てきた。前はすごく内気だった。", "D": "もっと社交的になる。"}},
308: {"nativeDefinition": "To argue about unimportant details.", "japaneseMeaning": "細かいことにこだわる、毛を裂く", "etymology": "split hairs（毛を裂く）の直訳的慣用表現。", "examples": {"B": "細かいことにこだわらないで。", "C": "毛を裂くような議論はやめよう。", "D": "小さな細部にうるさすぎる。"}},
309: {"nativeDefinition": "Except for; apart from.", "japaneseMeaning": "〜は別として、〜を除いて", "etymology": "aside（脇に）で、例外として取り除く意味。", "examples": {"B": "天気は別として、パーティーは成功した。", "C": "彼は別として、みんな賛成した。", "D": "何かを除いて。"}},
310: {"nativeDefinition": "An uncertain situation with equal chances.", "japaneseMeaning": "五分五分、コイントス", "etymology": "coin-flip（コイン投げ）の比喩で、50対50の不確実性。", "examples": {"B": "勝てるかどうかは五分五分だ。", "C": "結果はコイントスみたいにわからない。", "D": "不確実な状況。"}},
311: {"nativeDefinition": "A hypothetical question used to explore ideas.", "japaneseMeaning": "思考実験、仮定の質問", "etymology": "thought experiment（思考実験）の哲学用語。", "examples": {"B": "思考実験だけど、もしお金がなかったら？", "C": "仮定の質問だけど、時間旅行できたら何する？", "D": "仮想的な質問。"}},
312: {"nativeDefinition": "Directly; confronting something openly.", "japaneseMeaning": "正面から、直撃で", "etymology": "head-on（正面から）の直訳的表現。", "examples": {"B": "問題に正面から向き合う。", "C": "正面衝突を避けよう。", "D": "直接。"}},
313: {"nativeDefinition": "Having a close, informal relationship with someone.", "japaneseMeaning": "（人と）名前で呼び合う仲、親しい関係", "etymology": "on a first name basis（名前で呼び合う関係）の表現。", "examples": {"B": "上司と名前で呼び合う仲になった。", "C": "彼とはかなり親しい。名前で呼び合う。", "D": "誰かと親しい関係にある。"}},
314: {"nativeDefinition": "Still alive, active, and doing well.", "japaneseMeaning": "まだ健在、元気にやってる", "etymology": "alive and kicking（生きて蹴っている）の強調表現。", "examples": {"B": "祖父は90歳だけどまだ健在。", "C": "あのバンド、まだ元気にやってる。", "D": "活発に存在する。"}},
315: {"nativeDefinition": "And other similar things; et cetera.", "japaneseMeaning": "などなど、〜とか", "etymology": "what-not（何とか）の口語的表現。", "examples": {"B": "本、雑誌、なんでもいいよ。", "C": "コーヒー、紅茶、なんでも。", "D": "など。"}},
316: {"nativeDefinition": "As the proverb or saying goes.", "japaneseMeaning": "ことわざにあるように、言うように", "etymology": "as the saying goes（ことわざにあるように）の前置き表現。", "examples": {"B": "ことわざにあるように、時は金なり。", "C": "言うように、継続は力なり。", "D": "格言が言うように。"}},
317: {"nativeDefinition": "Even unreliable things can occasionally be right.", "japaneseMeaning": "時々当たる時もある、壊れた時計も二度は正しい", "etymology": "broken clock is right twice a day（壊れた時計も1日2回は正しい）のことわざ。", "examples": {"B": "株価予測、今回は当たった。壊れた時計も二度は正しい。", "C": "彼の言うことはほとんどデタラメだけど、時々当たる。壊れた時計も二度は正しい。", "D": "普段当てになない人や物も時々正しい。"}},
318: {"nativeDefinition": "Always late for everything.", "japaneseMeaning": "いつも遅刻する、自分の葬式に遅れそう", "etymology": "late for one's own funeral（自分の葬式に遅れる）の誇張表現。", "examples": {"B": "オーウェンはいつも遅刻するけど、辛い時は一緒にいてくれる大切な友達。", "C": "ダンはどこ？あいつ、自分の葬式に遅れそうなんだから。", "D": "いつも遅刻する。"}},
319: {"nativeDefinition": "Exceptionally good or impressive.", "japaneseMeaning": "すごい、別格", "etymology": "something else（別の何か）が「並外れて良い」の強調用法。", "examples": {"B": "スターバックスの接客は別格。いつもお客を笑顔にする。", "C": "たくさんヘッドホン試したけど、これは別格。コスパもいい。", "D": "並外れて良い。"}},
320: {"nativeDefinition": "To earn money to support a household.", "japaneseMeaning": "家計を支える、稼いでくる", "etymology": "bring home the bacon（ベーコンを持ち帰る）の古い慣用表現。", "examples": {"B": "男には家計を支えるプレッシャーがまだあると思う。", "C": "最近調子悪いけど、今夜は勝って家計に貢献したい。全力出す。", "D": "家計のために稼ぐ。"}},
321: {"nativeDefinition": "To take a seat.", "japaneseMeaning": "座って、椅子に座る", "etymology": "pull up a chair（椅子を引き寄せる）の直訳的表現。", "examples": {"B": "みんな座って。もうすぐディナーの準備できる。", "C": "座って一緒に映画見よう。", "D": "座る。"}},
322: {"nativeDefinition": "A choice between only two options.", "japaneseMeaning": "二者択一、どちらか一方", "etymology": "either-or（どちらか）の論理用語。", "examples": {"B": "キャリアと子育ては二者択一じゃない。両立できる。", "C": "質と量、どちらか一方じゃない。バランスだ。", "D": "二択。"}},
323: {"nativeDefinition": "To become suddenly very popular.", "japaneseMeaning": "（〜で）大ブームになる、席巻する", "etymology": "take by storm（嵐のように襲う）の比喩。", "examples": {"B": "あのPPAPソング、インターネットを席巻したのに1年くらいで消えた。", "C": "ポケモンGOは数年前世界を席巻した。まだやってる人いる？", "D": "突然とても流行る。"}},
324: {"nativeDefinition": "To reveal a secret accidentally or deliberately.", "japaneseMeaning": "（秘密を）漏らす、バラす", "etymology": "let the cat out of the bag（袋から猫を出す）の慣用表現。", "examples": {"B": "サプライズでカメを飼うの妻に内緒にしてたのに、グレッグがバラしちゃった。", "C": "辞めること内緒にしたいならニーナに言うなよ。絶対バラす。", "D": "秘密を明かす。"}},
325: {"nativeDefinition": "To stop a habitual behavior.", "japaneseMeaning": "（習慣を）断つ、やめる", "etymology": "break a habit（習慣を壊す）の直訳的表現。", "examples": {"B": "彼女と同棲する前に喫煙をやめたい。今しかない。", "C": "仕事後にポテチ食べる習慣、まだ断ててない。良い点は水をたくさん飲むようになったこと。", "D": "何かをやめる。"}},
}
